import Foundation

// MARK: - CaptionTrack

/// A single caption track as returned by YouTube's /player InnerTube endpoint.
/// Each track provides a WebVTT file at `baseURL` containing time-coded text cues.
public struct CaptionTrack: Identifiable, Hashable, Sendable {
    public let id: String               // vssId, e.g. ".en" or "a.en"
    public let baseURL: URL
    public let name: String             // Localised display name, e.g. "English"
    public let languageCode: String     // ISO 639-1, e.g. "en"
    public let isAutoGenerated: Bool    // true when vssId starts with "a." or kind == "asr"
}

// MARK: - CaptionCue

/// A single timed text segment parsed from a WebVTT file.
public struct CaptionCue: Sendable {
    public let startTime: TimeInterval
    public let endTime: TimeInterval
    public let text: String
}

// MARK: - WebVTTParser

/// Downloads and parses a WebVTT subtitle track.
/// Designed as an `actor` so concurrent fetches are safe.
public actor WebVTTParser {
    private let session: URLSession

    public init(session: URLSession = .shared) {
        self.session = session
    }

    /// Fetches and parses the VTT file at `url`. Returns cues sorted by start time.
    public func fetchCues(from url: URL) async throws -> [CaptionCue] {
        var request = URLRequest(url: url)
        request.setValue("text/vtt, */*", forHTTPHeaderField: "Accept")
        let (data, _) = try await session.data(for: request)
        guard let text = String(data: data, encoding: .utf8) else {
            throw URLError(.cannotDecodeContentData)
        }
        return parseVTT(text)
    }

    // MARK: - VTT parsing

    /// Parses a WebVTT string into `CaptionCue` values.
    /// Handles:
    ///   - WEBVTT header / NOTE / STYLE blocks
    ///   - Optional cue identifier lines
    ///   - Timestamp lines: "HH:MM:SS.mmm --> HH:MM:SS.mmm [settings]"
    ///   - Multi-line cue text
    ///   - `<...>` inline tags (stripped) and common HTML entities (decoded)
    nonisolated public func parseVTT(_ text: String) -> [CaptionCue] {
        var cues: [CaptionCue] = []
        let lines = text.components(separatedBy: .newlines)
        var i = 0

        // Skip the mandatory WEBVTT header line and any initial metadata
        while i < lines.count, !lines[i].contains("-->") { i += 1 }

        while i < lines.count {
            let line = lines[i].trimmingCharacters(in: .whitespaces)

            // Blank line → separator between cue blocks; advance
            if line.isEmpty { i += 1; continue }

            // If this line looks like a cue identifier (no "-->"), skip it
            if !line.contains("-->") { i += 1; continue }

            // Timestamp line: "00:00:01.000 --> 00:00:03.000 align:start size:95%"
            let arrowParts = line.components(separatedBy: " --> ")
            guard arrowParts.count >= 2,
                  let start = parseVTTTimestamp(arrowParts[0].trimmingCharacters(in: .whitespaces)),
                  let end = parseVTTTimestamp(
                    arrowParts[1]
                        .components(separatedBy: " ")
                        .first ?? ""
                  )
            else { i += 1; continue }

            i += 1

            // Collect text lines until blank line or end of file
            var textLines: [String] = []
            while i < lines.count {
                let tl = lines[i].trimmingCharacters(in: .whitespaces)
                if tl.isEmpty { break }
                textLines.append(tl)
                i += 1
            }

            let raw = textLines.joined(separator: "\n")
            let cleaned = stripVTTTags(raw).decodingHTMLEntities()
                .trimmingCharacters(in: .whitespacesAndNewlines)
            if !cleaned.isEmpty {
                cues.append(CaptionCue(startTime: start, endTime: end, text: cleaned))
            }
        }

        return cues.sorted { $0.startTime < $1.startTime }
    }

    // MARK: - Timestamp parsing

    /// Parses a VTT timestamp "HH:MM:SS.mmm" or "MM:SS.mmm" into seconds.
    nonisolated private func parseVTTTimestamp(_ s: String) -> TimeInterval? {
        let parts = s.components(separatedBy: ":")
        switch parts.count {
        case 2:
            guard let m = Double(parts[0]), let sec = Double(parts[1]) else { return nil }
            return m * 60 + sec
        case 3:
            guard let h = Double(parts[0]),
                  let m = Double(parts[1]),
                  let sec = Double(parts[2]) else { return nil }
            return h * 3600 + m * 60 + sec
        default:
            return nil
        }
    }

    // MARK: - Tag stripping

    /// Removes VTT inline tags: `<00:00:01.234>`, `<c.yellow>`, `<b>`, `</b>`, etc.
    nonisolated private func stripVTTTags(_ s: String) -> String {
        var result = ""
        result.reserveCapacity(s.count)
        var inTag = false
        for ch in s {
            if ch == "<" { inTag = true }
            else if ch == ">" { inTag = false }
            else if !inTag { result.append(ch) }
        }
        return result
    }
}

// MARK: - HTML entity decoding

private extension String {
    func decodingHTMLEntities() -> String {
        self
            .replacingOccurrences(of: "&amp;", with: "&")
            .replacingOccurrences(of: "&lt;", with: "<")
            .replacingOccurrences(of: "&gt;", with: ">")
            .replacingOccurrences(of: "&quot;", with: "\"")
            .replacingOccurrences(of: "&#39;", with: "'")
            .replacingOccurrences(of: "&nbsp;", with: " ")
            .replacingOccurrences(of: "&#x27;", with: "'")
            .replacingOccurrences(of: "&#x2F;", with: "/")
    }
}
